    vaultAuthority?: TAccountMetas[4] | undefined;
    clientTokenAccount?: TAccountMetas[5] | undefined;
    platformTreasury?: TAccountMetas[6] | undefined;
    tokenProgram?: TAccountMetas[7] | undefined;
